import { BrowserRouter, Link, Route, Routes } from "react-router-dom";
import { Home } from "./pages/Home.js";
import { About } from "./pages/About.js";

export function App() {
  return (
    <BrowserRouter>
      <nav className="flex gap-4 border-b border-slate-200 px-4 py-3 text-sm">
        <Link to="/">Home</Link>
        <Link to="/about">About</Link>
      </nav>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
      </Routes>
    </BrowserRouter>
  );
}

export function Home() {
  return (
    <main className="mx-auto max-w-3xl px-4 py-8">
      <h1 className="text-2xl font-semibold">Home</h1>
      <p className="mt-2 text-sm text-slate-600">Replace this with real home content.</p>
    </main>
  );
}

export function About() {
  return (
    <main className="mx-auto max-w-3xl px-4 py-8">
      <h1 className="text-2xl font-semibold">About</h1>
      <p className="mt-2 text-sm text-slate-600">Tell visitors who you are here.</p>
    </main>
  );
}
